def is_prime(n, use_cache=True):
    """
    Check if n is a prime number, with optional caching.

    Args:
        n: The number to check
        use_cache: Whether to use caching for faster repeated checks

    Returns:
        bool: True if n is prime, False otherwise
    """
    # Static cache as a function attribute
    if not hasattr(is_prime, 'cache'):
        is_prime.cache = {}

    # Check cache first if enabled
    if use_cache and n in is_prime.cache:
        return is_prime.cache[n]

    # Handle base cases
    if n < 2:
        result = False
    elif n == 2:
        result = True
    elif n % 2 == 0:
        result = False
    else:
        # Check odd divisors up to sqrt(n)
        result = True
        for i in range(3, int(n**0.5) + 1, 2):
            if n % i == 0:
                result = False
                break

    # Cache result if enabled
    if use_cache:
        is_prime.cache[n] = result

    return result

